import{_ as t,o as a,c as o,aw as d}from"./chunks/framework.DLufY-ao.js";const u=JSON.parse('{"title":"Теги HTML5 Layout","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/layout/html/tags/header.md","filePath":"wiki/dev-commit/layout/html/tags/header.md"}'),l={name:"wiki/dev-commit/layout/html/tags/header.md"};function r(i,e,c,n,h,g){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="теги-html5-layout" tabindex="-1">Теги HTML5 Layout <a class="header-anchor" href="#теги-html5-layout" aria-label="Permalink to &quot;Теги HTML5 Layout&quot;">​</a></h1><h2 id="элементы" tabindex="-1">Элементы <a class="header-anchor" href="#элементы" aria-label="Permalink to &quot;Элементы&quot;">​</a></h2><h3 id="header-header" tabindex="-1"><code>&lt;header&gt;&lt;/header&gt;</code> <a class="header-anchor" href="#header-header" aria-label="Permalink to &quot;`&lt;header&gt;&lt;/header&gt;`&quot;">​</a></h3><p>Элемент <code>&lt;header&gt;</code> задаёт «шапку» сайта или раздела, в которой обычно располагается заголовок</p><h3 id="nav-nav" tabindex="-1"><code>&lt;nav&gt;&lt;/nav&gt;</code> <a class="header-anchor" href="#nav-nav" aria-label="Permalink to &quot;`&lt;nav&gt;&lt;/nav&gt;`&quot;">​</a></h3><p>Элемент <code>&lt;nav&gt;</code> задаёт навигацию по сайту. Если на странице несколько блоков ссылок, то в <code>&lt;nav&gt;</code> обычно помещают приоритетные ссылки. Также допустимо использовать несколько <code>&lt;nav&gt;</code> в документе. Запрещается вкладывать <code>&lt;nav&gt;</code> внутрь <code>&lt;address&gt;</code></p><h3 id="main-main" tabindex="-1"><code>&lt;main&gt;&lt;/main&gt;</code> <a class="header-anchor" href="#main-main" aria-label="Permalink to &quot;`&lt;main&gt;&lt;/main&gt;`&quot;">​</a></h3><p>Элемент <code>&lt;main&gt;</code> предназначен для основного содержимого документа. На странице может быть только один <code>&lt;main&gt;</code> и он не должен располагаться внутри элементов <code>&lt;article&gt;</code>, <code>&lt;aside&gt;</code>, <code>&lt;footer&gt;</code>, <code>&lt;header&gt;</code> или <code>&lt;nav&gt;</code>.</p><h3 id="section-section" tabindex="-1"><code>&lt;section&gt;&lt;/section&gt;</code> <a class="header-anchor" href="#section-section" aria-label="Permalink to &quot;`&lt;section&gt;&lt;/section&gt;`&quot;">​</a></h3><p>Задаёт раздел документа, может применяться для блока новостей, контактной информации, глав текста, вкладок в диалоговом окне и др. Раздел обычно содержит заголовок.</p><h3 id="footer-footer" tabindex="-1"><code>&lt;footer&gt;&lt;/footer&gt;</code> <a class="header-anchor" href="#footer-footer" aria-label="Permalink to &quot;`&lt;footer&gt;&lt;/footer&gt;`&quot;">​</a></h3><p>Тег <code>&lt;footer&gt;</code> задаёт «подвал» сайта или раздела, в нём может располагаться имя автора, дата документа, контактная и правовая информация.</p><h3 id="article-article" tabindex="-1"><code>&lt;article&gt;&lt;/article&gt;</code> <a class="header-anchor" href="#article-article" aria-label="Permalink to &quot;`&lt;article&gt;&lt;/article&gt;`&quot;">​</a></h3><p>Задаёт содержание сайта вроде новости, статьи, записи блога, форума и др.</p><h3 id="aside-aside" tabindex="-1"><code>&lt;aside&gt;&lt;/aside&gt;</code> <a class="header-anchor" href="#aside-aside" aria-label="Permalink to &quot;`&lt;aside&gt;&lt;/aside&gt;`&quot;">​</a></h3><p>Определяет блок сбоку от контента для размещения рубрик, ссылок на архив, меток и другой информации. Такой блок, как правило, называется «сайдбар» или «боковая панель».</p><h3 id="figure-figure" tabindex="-1"><code>&lt;figure&gt;&lt;/figure&gt;</code> <a class="header-anchor" href="#figure-figure" aria-label="Permalink to &quot;`&lt;figure&gt;&lt;/figure&gt;`&quot;">​</a></h3><p>Используется для группирования любых элементов, например, изображений и подписей к ним. <code>&lt;figure&gt;</code> не должен быть связан непосредственно с основным содержимым документа и при его перемещении в другое место смысл текста не должен меняться. Обычно применяется для иллюстраций, фрагментов кода, схем, графиков, диаграмм и др.</p>',18)])])}const m=t(l,[["render",r]]);export{u as __pageData,m as default};
